final:
module RefModule (
    input [1:0] sel,
    input [3:0] in,
    output reg out
);
  wire [1:0] _tap_sel = sel & {2{1'b1}};


always @(*) begin
    case (sel)
        2'b00: out = in[0];
        2'b01: out = in[1];
        2'b10: out = in[2];
        2'b11: out = in[3];
    endcase
end

endmodule
